        }
        .page-container {
            margin: 10px auto;
            width: fit-content;
        }
        .page {
            overflow: hidden;
            position: relative;
            background-color: white;
        }
        .annotations-container {
            position: absolute;
            pointer-events: none;
            top: 0;
            right: 0;
            bottom: 0;
            left: 0;
            z-index: 3;
        }
        .annotations-container > div {
            position: absolute; pointer-events: auto; -webkit-user-select: none;
        }
        .annotations-container > div:hover {
            background-color: rgba(255, 255, 0, 0.25);
            cursor: pointer;
        }
